#include <bits/stdc++.h>
using namespace std;
void mysort(int q[],int l,int r) {
	if (l >= r) {
		return;
	}
	int i = l - 1, j = r + 1, x = q[l + r >> 1];
	while (i < j) {
		do i ++ ;
		while (q[i] < x);
		do j -- ;
		while (q[j] > x);
		if (i < j) {
			swap(q[i], q[j]);
		}
	}
	mysort(q,l,j);
	mysort(q,j+1,r);
}
int q[1000009];
int main() {
	int n;
	cin>>n;
	for(int i=0; i<n; i++) {
		cin>>q[i];
	}
	mysort(q,0,n-1);
	for(int i=0; i<n; i++) {
		cout<<q[i]<<" ";
	}
	return 0;
}
